import React from "react";
import Topnav from "../components/Topnav";
import Footer from "../components/Footer";
import background from '../assets/background.png'; // ← use your own marble/abstract bg here if you have one

function Landingpage() {
  return (
    <>
      <Topnav />

      {/* Hero Section - exactly matching the style you showed */}
      <section 
        className="relative min-h-screen flex items-center justify-center bg-cover bg-center"
        style={{ 
          backgroundImage: `url(${background})`, // or use a better fluid marble/ink/abstract image
        }}
      >
        {/* Optional subtle overlay to improve text readability */}
        <div className="absolute inset-0 bg-black/30"></div>

        <div className="relative z-10 max-w-5xl mx-auto px-6 text-center text-white">
          <h1 className="text-5xl sm:text-6xl md:text-7xl font-bold tracking-tight mb-6 leading-tight">
            Discover Your Gemstone
            <span className="block text-blue-400 mt-2 md:mt-4">
              With AI Precision
            </span>
          </h1>

          <p className="text-lg sm:text-xl md:text-2xl text-slate-200 max-w-4xl mx-auto mb-10 md:mb-12 leading-relaxed">
            Upload a photo and let GemAnalyzer instantly identify the gem type,<br className="hidden sm:inline" />
            cut, and quality using advanced artificial intelligence.
          </p>

          <a
            href="/imageuploader"
            className="inline-flex items-center px-10 py-5 md:px-12 md:py-6 
                       bg-blue-600 hover:bg-blue-500 
                       text-white text-lg md:text-xl font-semibold 
                       rounded-full shadow-2xl shadow-blue-900/40 
                       transition-all duration-300 transform hover:scale-105"
          >
            Start Analyzing Now →
          </a>
        </div>
      </section>

      <Footer />
    </>
  );
}

export default Landingpage;
